-- ============================================================================
-- 0022_restore_lost_historical_invoices.sql
--
-- BACKGROUND
--   Migration 0015 loaded ~11,400 historical invoice rows from per_meter_final.
--   Migration 0017 added a unique index on source_reference to prevent the
--   double-insert of 0015c. That unique constraint was too strict: source_ref
--   format was `historical-{year}-{prop}-{gl}-{account}-{month:02d}` — but
--   some (prop, gl, account, year, month) combinations legitimately have
--   multiple distinct invoice rows in per_meter_final:
--
--     * GL 5620 (FedEx): same Sage account billed multiple times per month
--       for separate shipments. Walton Reserve Jan '26 had 3 distinct rows
--       totaling $252.52, but only 1 ($10.95) survived dedupe.
--     * GL 5114 (Vacant electric): one master Sage account at properties
--       like Onion Creek bills allocations to ~90 vacant units per month;
--       these are the same account but different unit-level charges.
--     * Stragglers in GL 5116, 5120, 5125.
--
--   Net effect: 1,577 historical invoice rows were lost across 102 multi-row
--   groups. Tracker totals undercounted, variance baselines were off.
--
-- WHAT THIS MIGRATION DOES
--   Re-inserts the missing rows. For each multi-row group of size N, row 1
--   (already in DB) keeps its original source_reference. Rows 2..N are inserted
--   with `-r2`, `-r3`, …, `-rN` appended to the source_reference so the unique
--   index from 0017 is satisfied.
--
--   Mirrors the column choices and conventions of 0015c so the new rows are
--   indistinguishable from the originals: status = posted_to_sage, source =
--   manual, exclude_from_baseline = false, dates derived from year/month.
--
--   Vendor + utility_account lookup uses the CURRENT UA (post 0018/0020/0021
--   remap), so the inserted invoices land on the real vendor UAs already in
--   place.
--
-- DRY-RUN CHECK
--   The migration aborts if any per_meter row can't resolve to a (property,
--   gl, utility_account) triplet — this would mean schema drift since 0015.
-- ============================================================================

do $migration$
declare
  v_pending          int;
  v_unresolvable     int;
  v_inserted         int;
begin

  -- Stage the missing rows --------------------------------------------------

  create temp table _missing_invoices (
    property_code     text,
    gl_account_code   int,
    account_number    text,
    year              int,
    month             int,
    amount            numeric,
    source_reference  text
  ) on commit drop;


  select count(*) into v_pending from _missing_invoices;
  raise notice '[0022] Staged % missing invoice rows.', v_pending;

  -- Resolve UA + vendor for each row ----------------------------------------

  create temp table _resolved on commit drop as
  select
    mi.*,
    p.id  as property_id,
    g.id  as gl_account_id,
    ua.id as utility_account_id,
    ua.vendor_id
  from _missing_invoices mi
  left join properties     p  on p.code = mi.property_code
  left join gl_accounts    g  on g.code = mi.gl_account_code::text
  left join utility_accounts ua
         on ua.property_id   = p.id
        and ua.gl_account_id = g.id
        and ua.account_number is not distinct from mi.account_number;

  select count(*) into v_unresolvable
    from _resolved
   where utility_account_id is null
      or vendor_id is null;

  if v_unresolvable > 0 then
    raise notice '[0022] WARNING: % rows could not resolve to a (property, gl, utility_account, vendor). Listing them and skipping (showing up to 50):', v_unresolvable;
    declare
      r record;
    begin
      for r in (
        select
          property_code, gl_account_code, account_number, year, month, amount,
          (case when property_id is null         then 'no property'
                when gl_account_id is null       then 'no gl_account'
                when utility_account_id is null  then 'no utility_account for (prop,gl,acct)'
                when vendor_id is null           then 'UA found but vendor_id is NULL'
                else 'unknown'
           end) as reason
        from _resolved
        where utility_account_id is null or vendor_id is null
        order by property_code, gl_account_code, account_number, year, month
        limit 50
      ) loop
        raise notice '  prop=% gl=% acct="%" %-% amt=% -> %',
          r.property_code, r.gl_account_code, r.account_number,
          r.year, lpad(r.month::text, 2, '0'), r.amount, r.reason;
      end loop;
    end;
  else
    raise notice '[0022] All % rows resolved cleanly.', v_pending;
  end if;

  -- Insert -------------------------------------------------------------------

    utility_account_id, property_id, vendor_id, gl_account_id,
    invoice_number, invoice_date, service_period_start, service_period_end,
    current_charges, total_amount_due, gl_coding,
    status, source, source_reference,
    submitted_at, approved_at, sage_posted_at,
    exclude_from_baseline
  )
  select
    r.utility_account_id,
    r.property_id,
    r.vendor_id,
    r.gl_account_id,
    r.source_reference,
    make_date(r.year, r.month, 15),
    make_date(r.year, r.month, 1),
    (make_date(r.year, r.month, 1) + interval '1 month' - interval '1 day')::date,
    r.amount,
    r.amount,
    '500-' || r.property_code || '-' || r.gl_account_code::text || '.00',
    'posted_to_sage'::invoice_status,
    'manual',
    r.source_reference,
    now(),
    now(),
    now(),
    false
  from _resolved r
  where r.utility_account_id is not null
    and r.vendor_id is not null
  on conflict (source_reference) where source_reference like 'historical-%' do nothing;

  get diagnostics v_inserted = row_count;

  raise notice '[0022] Inserted % missing historical invoices (% staged, % unresolvable, % already existed).',
    v_inserted, v_pending, v_unresolvable, v_pending - v_unresolvable - v_inserted;

end $migration$;
